const Q_BIOLOGY_2001=[{"id": "objective>Biology>2001>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water fleas, wood lice and barnacles belong to the group</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">insecta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chilopoda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crustacea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arachnida</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water fleas, wood lice and barnacles belong to the group 'Crustacea'. Crustaceans are a large group of arthropods, which includes such familiar animals as crabs, lobsters, crayfish, shrimp, krill, wood lice, and barnacles.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2001>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms does not exist as a single free living cell?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volvox</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlamydomonas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paramecium</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volvox does not exist as a single free-living cell. It is a genus of chlorophytes, a type of green algae. It forms spherical colonies of up to 50,000 cells. They live in a variety of freshwater habitats, and were first reported by Antonie van Leeuwenhoek in 1700.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2001>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An association between the root nodule of a leguminous plant and <span style=\"font-style:italic;\"> Rhizobium sp. </span>is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">symbiosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commensalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mycorrhiza</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The association between the root nodule of a leguminous plant and <span style=\"font-style:italic;\"> Rhizobium sp. </span>is known as 'Symbiosis'. Symbiosis is a close and long-term biological interaction between two different biological organisms. In this case, Rhizobium bacteria in the soil infect the roots of leguminous plants, leading to the formation of root nodules where the bacteria fix atmospheric nitrogen into a form that the plant can use.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2001>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups is the most advanced?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thallophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pteridophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gymnosperms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bryophytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gymnosperms are the most advanced among the given options. The order of advancement in plant groups is Thallophytes < Bryophytes < Pteridophytes < Gymnosperms. Gymnosperms are seed-producing plants, and their seeds are not enclosed within an ovary, unlike angiosperms. They are more advanced than the other options because they have a well-differentiated plant body and vascular tissues for the transport of water, minerals, and food.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>2001>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of feeding in Amoeba and Hydra is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">autotrophic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heterotrophic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">symbiotic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holophytic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of feeding in both Amoeba and Hydra is heterotrophic. Heterotrophic organisms are those that cannot synthesize their own food and depend on other organisms for their nutrition. Amoeba and Hydra both consume their food by engulfing it, a process known as phagocytosis.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2001>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Viviparity occurs mainly in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amphibians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mammals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reptiles</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Viviparity, the mode of reproduction in which the embryo develops inside the body of the mother, occurs mainly in mammals. In this mode of reproduction, the young ones are born alive and not from eggs. This is a characteristic feature of mammals, although there are exceptions in other groups.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2001>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> In ferns, the structure above is equivalent to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gametophyte generation of a moss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sporophyte generation of a moss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sporangium of a moss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zygote of a moss</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In mosses, the gametophyte generation is the dominant, photosynthetic phase. It begins with the protonema, a filamentous structure from which buds form. These buds develop into leafy shoots composed of stem-like caulidum, leaf-like phyllids, and rhizoids for anchorage. The gametophyte produces male (antheridia) and female (archegonia) reproductive organs at the shoot tips. Fertilization occurs when sperm swim to the archegonia, leading to the formation of a diploid sporophyte.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>2001>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structures labeled II and III respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sporophyte and sori</div>", "<div style=\"font-family:Cambria;font-size:17px;\">annulus and stalk of sporangium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">female organs and rhizoid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">male organs and rhizoid</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structures labeled II and III respectively are Male organs and rhizoid.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>2001>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Most monocots are easily recognized by their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">long and sword-like leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long and palm-like leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short leaves with petioles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short leaves with many veinlets</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monocots, short for monocotyledons, are a type of flowering plant that typically have long, narrow, and sword-like leaves. This is a characteristic feature of many monocots, including grasses and grains. The leaves are usually parallel-veined, another distinguishing feature of monocots.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2001>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Amphibians are normally found</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on moist land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in water and moist land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on dry land and in water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amphibians are a group of cold-blooded vertebrates that includes frogs, toads, newts, and salamanders. They are adapted to live both in water and on moist land. They typically start their life cycle in water with gills and tails, like fish, and then undergo metamorphosis, developing lungs and legs for living on land. However, they still need a moist environment to survive, as their skin must stay wet.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2001>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The jointed structure in insects that bears organs which are sensitive to touch, smell and vibration is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">antenna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abdomen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maxilla</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labium</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In insects, the antenna is a jointed structure that bears organs which are sensitive to touch, smell, and vibration. It is a sensory appendage that is attached to the head of adult insects. Antennae are used for the sense of smell and balance. They are jointed, and the number of segments can vary between species.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2001>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The veins of the leaf are formed by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spongy mesophyll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">palisade tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cambium cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vascular bundles</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The veins of the leaf are formed by the vascular bundles. Vascular bundles are a part of the transport system in plants. They are strands of tissue that run the length of the plant, from the roots, through the stem and out into the leaves. They are responsible for the transport of water, minerals, and food throughout the plant.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2001>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When specimen X is mixed with few drops of iodine solution, the appearance of a blue-black colour confirms X is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sucrose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">galactose</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When iodine solution is mixed with a specimen and a blue-black color appears, it confirms that the specimen contains starch. Iodine solution is used as a test for the presence of starch. Starch reacts with iodine to form a blue-black complex, hence the change in color.</div>", "topic": "NUTRITION : TYPES OF NUTRITION"}, {"id": "objective>Biology>2001>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme invertase will hydrolyze sucrose to give</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mannose and galactose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose and fructose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maltose and glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glycerol and fatty acid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme invertase hydrolyzes sucrose to give glucose and fructose. Invertase is an enzyme that catalyzes the hydrolysis (breakdown with the addition of a water molecule) of sucrose, a disaccharide, into the monosaccharides glucose and fructose.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2001>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Salts and water are absorbed in the roots and transported to the leaves by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">osmosis through the phloem tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion through the phloem tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmosis through the xylem tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion through the xylem tissues</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Salts and water are absorbed in the roots and transported to the leaves by osmosis through the xylem tissues. Xylem is a type of tissue in vascular plants that transports water and some nutrients from the roots to the leaves. Osmosis is the process by which molecules of a solvent tend to pass from a less concentrated solution into a more concentrated one, equalizing the concentrations on each side of a biological membrane.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2001>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The transportation of oxygen and carbon(IV) oxide in mammals is carried out by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phagocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leucocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erythrocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thrombocytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The transportation of oxygen and carbon(IV) oxide in mammals is carried out by erythrocytes. Erythrocytes, also known as red blood cells, are the most common type of blood cell and the vertebrate's principal means of delivering oxygen to the body tissues via the blood flow through the circulatory system.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2001>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas produced during tissues respiration can be identified by using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium carbonate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper sulphate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium hydroxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gas produced during tissues respiration can be identified by using calcium hydroxide. Calcium hydroxide, also known as limewater, is used to test for the presence of carbon dioxide. In the presence of carbon dioxide, limewater turns milky or cloudy, which is a positive test.</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>2001>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When yeast respires anaerobically it converts simple sugars to Carbon (IV) Oxide and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alcohol</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During anaerobic respiration, yeast converts simple sugars into carbon dioxide and alcohol. This process is known as fermentation. It is a type of anaerobic respiration, which occurs in the absence of oxygen. The alcohol produced is ethanol.</div>", "topic": "RESPIRATION : ANAEROBIC RESPIRATION"}, {"id": "objective>Biology>2001>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Urea formation occurs in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liver </div>", "<div style=\"font-family:Cambria;font-size:17px;\">kidney </div>", "<div style=\"font-family:Cambria;font-size:17px;\">heart </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lung.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Urea formation occurs in the liver. This process is part of the urea cycle, where ammonia, a toxic substance, is converted into urea, a less toxic substance. The urea is then transported to the kidneys where it is excreted in urine.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2001>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure above represents a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thoracic vertebra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cervical vertebra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caudal vertebra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbar vertebra</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure above represents a cervical vertebra. It has a short neural spine.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2001>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Blood vessels usually pass through the structure labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">V.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Is vertebrarterial canal where blood vessels pass through.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2001>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labeled IV is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yolk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air space</div>", "<div style=\"font-family:Cambria;font-size:17px;\">albumen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">germinal disc</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Germinal disc is also known as the embryo and it is surrounded by the yolk.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2001>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure that holds the yolk in position is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure that holds the yolk in position is labelled III or Chalaza holds the yolk in position</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2001>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A seedling grown in the dark is likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sturdy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stunted </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dormant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">etiolated</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A seedling grown in the dark is likely to be etiolated. Etiolation is a process in flowering plants grown in partial or complete absence of light, which causes them to become pale, elongated, and weak due to rapid cell growth and elongation.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2001>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled II is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">internal auditory meatus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fenestra ovalis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ear ossicles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">middle ear canal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ear ossicles is located in the middle ear and they include malleus (hammer), stapes (stirrup) and incus (anvil).</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2001>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The parts which function together to bring about hearing are labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, IV and VI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV, V and VI.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> The external auditory meatus, the hammer, anvil, stirrup and the cochlea aids in hearing.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2001>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The center for learning and memory in the human brain is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">olfactory lobe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebrum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medulla oblongata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebellum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cerebrum is the largest part of the brain and is associated with higher brain function such as thought and action. It is divided into four sections, known as 'lobes': the frontal lobe, parietal lobe, occipital lobe, and temporal lobe. The temporal lobe is primarily involved in processing and interpreting sounds and also plays a key role in memory formation.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2001>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physical space occupied by an organism together with its functional role in the community can be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">niche </div>", "<div style=\"font-family:Cambria;font-size:17px;\">environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">habitat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">biome</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In ecology, a niche is the match of a species to a specific environmental condition. It describes how an organism or population responds to the distribution of resources and competitors (for example, by growing when resources are abundant, and when predators, parasites and pathogens are scarce) and how it in turn alters those same factors (for example, limiting access to resources by other organisms, acting as a food source for predators and a consumer of prey).</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2001>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hygrometer is used for measuring</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salinity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific gravity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hygrometer is an instrument used to measure the amount of humidity and water vapor in the atmosphere, in soil, or in confined spaces. Humidity measurement instruments usually rely on measurements of some other quantity such as temperature, pressure, mass, a mechanical or electrical change in a substance as moisture is absorbed.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2001>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest percentage of energy in an ecosystem occurs at level of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decomposer</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an ecosystem, the highest percentage of energy is found at the level of the producers. This is because producers, such as plants, are able to convert sunlight into usable energy through photosynthesis. This energy is then passed up the food chain to consumers and decomposers, but with each transfer, a significant amount of energy is lost, usually as heat. Therefore, the amount of energy decreases as you move up the food chain from producers to primary consumers, secondary consumers, and decomposers.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2001>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (IV) oxide content of the atmosphere is least affected by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">burning of fossil fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cutting down and clearing of forests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plant and animal respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forest fires</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Carbon (IV) oxide content of the atmosphere is least affected by plant and animal respiration. This is because the process of respiration in plants and animals is part of the natural carbon cycle. During respiration, Carbon (IV) oxide is released into the atmosphere, but it is also absorbed by plants during photosynthesis. Therefore, the net effect on the Carbon (IV) oxide content of the atmosphere is minimal. On the other hand, human activities such as burning of fossil fuels and deforestation significantly increase the Carbon (IV) oxide content of the atmosphere.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2001>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A freshwater pond may contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pond skater, water lily, shark and mosquito larva</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water lily, fish, water scorpion and dragonfly larva</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tad pole, water boatman, leeches and crab</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water beetle, shrimps, water snail and water bug</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A freshwater pond may contain water lily, fish, water scorpion, and dragonfly larva. These are all organisms that are adapted to live in freshwater environments. Sharks and crabs are marine animals and are not typically found in freshwater environments. Similarly, shrimps are usually found in saltwater environments. Pond skaters, leeches, water beetles, water snails, and water bugs can also be found in freshwater environments, but the combination of organisms listed in option 2 is the most likely to be found together in a freshwater pond.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2001>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The epiphytic habitat can best be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aquatic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">terrestrial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arboreal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">estuarine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Epiphytic habitat refers to the environment in which epiphytes live. Epiphytes are plants that grow on other plants, usually trees, without harming them. They are not parasitic but rely on their hosts for physical support. This type of habitat is best described as arboreal, which means 'pertaining to trees'.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2001>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distribution of plants in a rain forest is governed mainly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfall pattern</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil types</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amount of sunlight</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The distribution of plants in a rain forest is governed mainly by the rainfall pattern. In both temperate and tropical regions, the amount and distribution of rainfall, rather than temperature, determine the vegetation i.e whether it is a forest, a grassland or a desert.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2001>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of plant species obtained from a population study of a garden is as follows;  <br/>  Guinea grass (15), Ipomea spp. (5) Sida spp(7) and Imperata spp. (23). What is the percentage of occurrence of Imperata spp.?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">23% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">35% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">46%.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The percentage of occurrence of a species in a population can be calculated by dividing the number of individuals of that species by the total number of individuals in the population, and then multiplying the result by 100. In this case, the total number of plants is 15 (Guinea grass) + 5 (Ipomea spp.) + 7 (Sida spp.) + 23 (Imperata spp.) = 50. Therefore, the percentage of occurrence of Imperata spp. is (23/50) * 100 = 46%.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2001>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest influence on a stable ecosystem in nature is exhibited by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest influence on a stable ecosystem in nature is exhibited by man. This is because human activities such as deforestation, pollution, urbanization, etc., have a significant impact on the ecosystem. They can alter the balance of the ecosystem, leading to the extinction of certain species and the proliferation of others.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2001>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factor that least affects food shortage in sub-saharan Africa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drought </div>", "<div style=\"font-family:Cambria;font-size:17px;\">flooding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pests   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed–cropping</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The factor that least affects food shortage in sub-saharan Africa is mixed-cropping. Mixed cropping is a method of farming that involves planting two or more plants simultaneously in the same field, which can actually increase food production and contribute to food security. On the other hand, drought, flooding, and pests can significantly reduce food production.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2001>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In man, the ability to roll the tongue is a variation classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">structural</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morphological</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anatomical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physiological</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In man, the ability to roll the tongue is a variation classified as physiological. Physiological variations are differences in the function of an organism or the ability to perform a particular function. The ability to roll the tongue is a functional variation, not a structural, morphological, or anatomical one.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2001>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is true of blood groups and blood transfusion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Group A can donate to group A only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Group B can donate to group B only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Group O is the universal recipient</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Group AB is the universal recipient</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of blood transfusion, Group AB is considered the universal recipient because it can receive blood from donors of any ABO blood group (A, B, AB, or O). This is due to the fact that AB blood types do not have any antibodies against A or B antigens, thus they can receive blood from any group without causing an immune response.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2001>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tall plant crossed with a dwarf one produces offspring of which half are tall and half are dwarf. What are the genotypes of the parents?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tt, tt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">TT, tt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tt, Tt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">TT, TT</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2001/k1.png\" style=\"position:relative;max-width:100%;\"/> <br/> Hence we have : 2 Heterzygous tall and homozygous short. </div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2001>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Both recessive and dominant characters are found</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">at the same locus of a homologous chromosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at different loci of homologous chromosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on different chromosomes in the cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on the same chromatid in a chromosome</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both recessive and dominant characters are found at the same locus of a homologous chromosome. A locus is a specific location or position on a chromosome where a given gene is located. In a pair of homologous chromosomes, one from each parent, the same locus is the position for the same gene. This gene can be either dominant or recessive.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2001>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is likely to encourage inbreeding in plants</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monoecious</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dioecious</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hermaphrodite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protandrous</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hermaphrodite plants, which contain both male and female reproductive organs, are more likely to encourage inbreeding as they can self-fertilize.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2001>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The probability of a baby being a boy or a girl depends on the contribution of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mother's sex cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mother's X chromosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">father's sex cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">father's somatic chromosome.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sex of a baby is determined by the sex chromosome contributed by the father's sex cell (sperm). If the sperm carries an X chromosome, the baby will be female (XX). If the sperm carries a Y chromosome, the baby will be male (XY).</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2001>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of an organism to live successfully in an environment is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">succession </div>", "<div style=\"font-family:Cambria;font-size:17px;\">resistance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adaptation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptation is the ability of an organism to change over time in response to the environment. This can be a physical change in the organism's body or a change in the organism's behavior. This ability helps the organism to survive and reproduce in its environment.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2001>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For heterotrophic organisms, competition is least caused by inadequacy of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nutrients </div>", "<div style=\"font-family:Cambria;font-size:17px;\">light </div>", "<div style=\"font-family:Cambria;font-size:17px;\">space </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mates</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heterotrophic organisms are those that cannot manufacture their own food and need to obtain it from other organisms. This includes animals and fungi. They compete for resources such as nutrients, space, and mates. However, light is primarily a concern for autotrophic organisms (like plants) that use light for photosynthesis, not heterotrophs. Therefore, competition among heterotrophs is least caused by inadequacy of light.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2001>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important adaptation of xerophytes is the ability of the protoplasm to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorb water and swell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resist being damaged by water loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shrink from the cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">store sugar and minerals in the vacuoles</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Xerophytes are plants that are adapted to survive in dry environments with little water. The most important adaptation of xerophytes is their ability to resist being damaged by water loss. This is achieved through various physiological and structural adaptations such as having a thick cuticle, reduced leaf area, and the presence of sunken stomata.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2001>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stem of a typical aquatic plant usually has many</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water cavities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water-conducting cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air cavities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intercellular spaces</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aquatic plants, also known as hydrophytes, have adaptations that enable them to survive in water or in soil that is periodically underwater. One of these adaptations is the presence of air cavities, also known as aerenchyma, in their stems. These air cavities allow for the transportation of gases between the plant parts that are above water and those that are submerged.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2001>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A green snake in green grass is able to escape notice from predators because of its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">warning colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disruptive colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cryptic colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">countershading</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A green snake in green grass is able to escape notice from predators because of its cryptic colouration. Cryptic colouration, also known as camouflage, is a defensive adaptation that allows an organism to blend in with its surroundings. In this case, the green colour of the snake matches the green colour of the grass, making it difficult for predators to spot.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2001>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The role of the male adult honey bee is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mate with the queen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">care for the young</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clean the hive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ventilate the hive</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary role of the male adult honey bee, also known as a drone, is to mate with the queen. They do not have the ability to sting, and they do not participate in nectar and pollen gathering. A drone's primary role is to mate with a virgin queen. He has a barbed sex organ, which leads to his death after mating.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2001>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Darwin is considered the first scientist who correctly explained the theory of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">organic evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use and disuse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">special creation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spontaneous generation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Charles Darwin is most celebrated for his theory of evolution by natural selection, which explains how populations of organisms change over time through the process of descent with modification. This theory specifically focuses on organic or biological evolution, as opposed to other concepts like use and disuse, special creation, or spontaneous generation.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}];
